// ── Processar mensagem e gerenciar conversa ───────────────────────────────
const body = $input.first().json;

// Estrutura da Evolution API v2
const msgData = body.data;
if (!msgData) return [];

// Ignorar mensagens enviadas pelo próprio bot
if (msgData.key?.fromMe === true) return [];

// Ignorar se não houver mensagem de texto
const message = (
  msgData.message?.conversation ||
  msgData.message?.extendedTextMessage?.text ||
  msgData.message?.buttonsResponseMessage?.selectedDisplayText ||
  ''
).trim();

if (!message) return [];

// Extrair telefone
const phone = (msgData.key?.remoteJid || '').replace('@s.whatsapp.net', '');
if (!phone) return [];

// ── Estado da conversa (persiste no banco do N8N) ─────────────────────────
const staticData = $getWorkflowStaticData('global');
if (!staticData.conv) staticData.conv = {};

const conv = staticData.conv[phone] || { step: 0 };
const step = conv.step;

let reply = '';
let nextStep = step;

// ── Fluxo de perguntas ────────────────────────────────────────────────────
if (step === 0) {
  reply = 'Olá! Sou a assistente da Sety Studio. 👋\n\nVou te fazer 5 perguntas rápidas para entender seu projeto.\n\nQual é o seu nome?';
  nextStep = 1;

} else if (step === 1) {
  conv.nome = message;
  reply = `Prazer, ${message}! 😊\n\nQuando você quer lançar sua loja?\n\n1️⃣ Essa semana\n2️⃣ Este mês\n3️⃣ Em 3 meses\n4️⃣ Sem prazo definido`;
  nextStep = 2;

} else if (step === 2) {
  const map = { '1': 'Essa semana', '2': 'Este mês', '3': 'Em 3 meses', '4': 'Sem prazo definido' };
  conv.prazo = map[message] || message;
  reply = 'Qual faixa de investimento você considera?\n\n1️⃣ Até R$ 800\n2️⃣ R$ 800 a R$ 1.500\n3️⃣ R$ 1.500 a R$ 3.000\n4️⃣ Acima de R$ 3.000';
  nextStep = 3;

} else if (step === 3) {
  const map = { '1': 'Até R$ 800', '2': 'R$ 800 a R$ 1.500', '3': 'R$ 1.500 a R$ 3.000', '4': 'Acima de R$ 3.000' };
  conv.investimento = map[message] || message;
  reply = 'Você já tem fornecedor?\n\n1️⃣ Sim, já tenho\n2️⃣ Ainda buscando\n3️⃣ Não tenho';
  nextStep = 4;

} else if (step === 4) {
  const map = { '1': 'Sim, já tenho', '2': 'Ainda buscando', '3': 'Não tenho' };
  conv.fornecedor = map[message] || message;
  reply = 'Última pergunta! Qual plataforma prefere?\n\n1️⃣ Shopify\n2️⃣ Nuvemshop\n3️⃣ Não sei ainda';
  nextStep = 5;

} else if (step === 5) {
  const map = { '1': 'Shopify', '2': 'Nuvemshop', '3': 'Não sei ainda' };
  conv.plataforma = map[message] || message;

  // ── Calcular Score ─────────────────────────────────────────────────────
  let score = 0;

  if (conv.prazo === 'Essa semana') score += 25;
  else if (conv.prazo === 'Este mês') score += 20;
  else if (conv.prazo === 'Em 3 meses') score += 10;

  if (conv.investimento === 'Acima de R$ 3.000') score += 25;
  else if (conv.investimento === 'R$ 1.500 a R$ 3.000') score += 20;
  else if (conv.investimento === 'R$ 800 a R$ 1.500') score += 10;

  if (conv.fornecedor === 'Sim, já tenho') score += 25;
  else if (conv.fornecedor === 'Ainda buscando') score += 10;

  if (conv.plataforma === 'Shopify') score += 25;
  else if (conv.plataforma === 'Nuvemshop') score += 15;
  else score += 5;

  let classificacao, emoji;
  if (score >= 71) { classificacao = 'Lead Quente'; emoji = '\uD83D\uDD25'; }
  else if (score >= 41) { classificacao = 'Lead Morno'; emoji = '\uD83C\uDF21\uFE0F'; }
  else { classificacao = 'Lead Frio'; emoji = '\u2744\uFE0F'; }

  conv.score = score;
  conv.classificacao = classificacao;
  conv.emoji = emoji;
  conv.telefone = phone;
  conv.completed = true;

  const agora = new Date();
  agora.setHours(agora.getHours() - 3);
  conv.data_hora = agora.toISOString().replace('T', ' ').substring(0, 16);

  reply = `Perfeito! \uD83C\uDF89\n\nRecebi suas informações. Nossa equipe entrará em contato em breve com uma proposta personalizada.\n\nFique atento ao WhatsApp! \uD83D\uDCF1`;
  nextStep = 99;

} else {
  // Conversa já concluída — reiniciar
  staticData.conv[phone] = { step: 0 };
  reply = 'Olá! Sou a assistente da Sety Studio. 👋\n\nVou te fazer 5 perguntas rápidas. Qual é o seu nome?';
  nextStep = 1;
  conv.step = 1;
  staticData.conv[phone] = conv;
  return [{ json: { phone, reply, completed: false, conv: {} } }];
}

// Salvar estado atualizado
conv.step = nextStep;
staticData.conv[phone] = conv;

return [{
  json: {
    phone,
    reply,
    completed: nextStep === 99,
    nome: conv.nome || '',
    prazo: conv.prazo || '',
    investimento: conv.investimento || '',
    fornecedor: conv.fornecedor || '',
    plataforma: conv.plataforma || '',
    score: conv.score || 0,
    classificacao: conv.classificacao || '',
    emoji: conv.emoji || '',
    data_hora: conv.data_hora || '',
    telefone: phone
  }
}];

